import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation(); // Used to highlight the active terminal node

  // 1. Hide the navbar if no user is authenticated (prevents ghosting on login page)
  if (!user) return null;

  const handleExit = () => {
    try {
      logout();
      toast.success("TERMINAL_OFFLINE: ACCESS_REVOKED", {
        style: { borderRadius: '0px', background: '#121212', color: '#ff4b4b' }
      });
      navigate('/login');
    } catch (err) {
      // Fallback if state is already desynced
      localStorage.removeItem('token');
      window.location.href = '/login';
    }
  };

  // Helper to determine if a route is active
  const isActive = (path) => location.pathname === path;

  return (
    <nav className="p-4 border-b border-white/10 flex justify-between items-center bg-[#121212]/50 backdrop-blur-md sticky top-0 z-50">
      <div className="flex gap-10 items-center">
        {/* Brand Node */}
        <Link 
          to="/dashboard" 
          className="text-[#E0BBE4] font-bold tracking-tighter text-lg hover:opacity-80 transition-opacity"
        >
          FINIFY_AI
        </Link>
        
        {/* Navigation Matrix */}
        <div className="flex gap-6 text-[10px] uppercase tracking-[0.2em]">
          <Link 
            to="/dashboard" 
            className={`transition-colors ${isActive('/dashboard') ? 'text-[#E0BBE4]' : 'text-white/40 hover:text-white'}`}
          >
            [ dashboard ]
          </Link>
          <Link 
            to="/generate" 
            className={`transition-colors ${isActive('/generate') ? 'text-[#E0BBE4]' : 'text-white/40 hover:text-white'}`}
          >
            [ strategy_engine ]
          </Link>
        </div>
      </div>

      <div className="flex items-center gap-6">
        {/* User Identity Indicator */}
        <span className="text-[9px] text-white/20 hidden md:block uppercase tracking-widest">
          Node_ID: <span className="text-white/40">{user.email}</span>
        </span>

        {/* Termination Action */}
        <button 
          onClick={handleExit} 
          className="text-[10px] text-red-400/50 border border-red-400/20 px-3 py-1 rounded hover:bg-red-400/10 hover:text-red-400 transition-all uppercase"
        >
          EXIT_TERMINAL
        </button>
      </div>
    </nav>
  );
};

export default Navbar;
